interface Props {
  children: ReactNode;
  fallback?: ReactNode;
}

interface State {
  hasError: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  state: State = { hasError: false };

  static getDerivedStateFromError(): State {
    return { hasError: true };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    console.error('ErrorBoundary caught:', error, info);
  }

  render() {
    if (this.state.hasError) {
      return this.props.fallback ?? <p>문제가 발생했습니다.</p>;
    }
    return this.props.children;
  }
}

// 사용
const App = () => (
  <ErrorBoundary fallback={<ErrorFallbackUI />}>
    <ProductPage />
  </ErrorBoundary>
);`})]}),yC=()=>t.jsxs(t.Fragment,{children:[t.jsxs("div",{style:{background:"#e8f4fd",padding:"16px 20px",borderRadius:"8px",marginBottom:"24px",borderLeft:"4px solid #2196f3"},children:[t.jsx("strong",{children:"이전 챕터 연결:"})," Ch6에서 만든 API 연동 코드가 제대로 동작하는지 어떻게 확인할까요?",t.jsxs("p",{style:{margin:"8px 0 0"},children:["지금까지는 코드 수정 후 브라우저에서 직접 클릭하며 확인했죠. 테스트 코드를 작성하면 ",t.jsx("code",{children:"npm test"}),' 한 번으로 수십 가지를 자동 검증합니다. "이 버튼 누르면 이 텍스트가 나와야 해"를 코드로 적어두는 거예요.']})]}),t.jsx("h2",{children:"Jest / Vitest 기초 (단위 테스트)"}),t.jsxs("p",{children:[t.jsx("strong",{children:"Jest"}),"는 오랫동안 JavaScript 표준 테스트 프레임워크였고,",t.jsx("strong",{children:"Vitest"}),"는 Vite 기반의 차세대 테스트 러너로 2026년 현재 신규 프로젝트에서 가장 많이 선택됩니다. 두 도구의 API는 거의 동일하므로 하나를 배우면 다른 것도 바로 사용할 수 있습니다."]}),t.jsxs("div",{style:{background:"#f0f4ff",padding:"12px 16px",borderRadius:"8px",marginBottom:"16px",fontSize:"14px"},children:[t.jsx("strong",{children:"Jest vs Vitest (2026 기준)"}),t.jsxs("ul",{style:{margin:"8px 0 0",paddingLeft:"20px"},children:[t.jsxs("li",{children:[t.jsx("strong",{children:"Vitest"})," — Vite 프로젝트라면 기본 선택. TypeScript/ESM 네이티브 지원, 3~5배 빠른 실행"]}),t.jsxs("li",{children:[t.jsx("strong",{children:"Jest"})," — React Native, 레거시 프로젝트에서 여전히 표준. Jest 30 출시로 성능 개선"]}),t.jsxs("li",{children:["테스트 문법(describe, test, expect)은 ",t.jsx("strong",{children:"동일"})," — 아래 예제는 둘 다에서 작동"]})]})]}),t.jsx("h3",{children:"테스트 작성 기본 구조"}),t.jsx(N,{title:"첫 번째 테스트",language:"typescript",code:`// utils/format.ts
